func (s *Server) forwardToSandbox(c *gin.Context, sandboxInfo *types.SandboxInfo, path string) error {
	if len(sandboxInfo.EntryPoints) == 0 {
		c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
		return errors.New("no entry points")
	}

	var entryPoint *types.SandboxEntryPoint
	for _, ep := range sandboxInfo.EntryPoints {
		if ep.Path != "" && strings.HasPrefix(path, ep.Path) {
			entryPoint = &ep
			break
		}
	}
	if entryPoint == nil {
		entryPoint = &sandboxInfo.EntryPoints[0]
	}

	scheme := strings.ToLower(entryPoint.Protocol)
	if scheme == "" {
		scheme = "http"
	}

	targetURL := fmt.Sprintf("%s://%s", scheme, entryPoint.Endpoint)
	target, err := url.Parse(targetURL)
	if err != nil {
		return err
	}

	proxy := httputil.NewSingleHostReverseProxy(target)
	proxy.Transport = s.httpTransport

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = target.Scheme
		req.URL.Host = target.Host
		req.URL.Path = path
		if !strings.HasPrefix(path, "/") && path != "" {
			req.URL.Path = "/" + path
		}
		req.URL.RawPath = ""
		req.Host = target.Host

		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		proto := "http"
		if c.Request.TLS != nil {
			proto = "https"
		}
		req.Header.Set("X-Forwarded-Proto", proto)

		clientIP := c.ClientIP()
		if existing := req.Header.Get("X-Forwarded-For"); existing != "" {
			req.Header.Set("X-Forwarded-For", existing+", "+clientIP)
		} else {
			req.Header.Set("X-Forwarded-For", clientIP)
		}

		if sandboxInfo.Kind == types.SandboxKind || sandboxInfo.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": sandboxInfo.SessionID,
			})
			if err != nil {
				klog.Warningf("failed to generate JWT: %v", err)
			} else {
				req.Header.Set("Authorization", "Bearer "+token)
			}
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sandboxInfo.SessionID)
		return nil
	}

	proxy.ServeHTTP(c.Writer, c.Request)
	return nil
