	}

	return &manager{
		storeClient:     storeClient,
		workloadMgrAddr: addr,
		httpClient: &http.Client{
			Timeout: 2 * time.Minute,
			Transport: &http.Transport{
				MaxIdleConnsPerHost: 100,
				DisableCompression:  false,
			},
		},
	}, nil
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	if sessionID != "" {
		info, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
		if err != nil {
			if errors.Is(err, store.ErrNotFound) {
				return nil, api.NewSessionNotFoundError(sessionID)
			}
			return nil, err
		}
		return info, nil
	}

	var endpoint string
	if kind == types.AgentRuntimeKind {
		endpoint = fmt.Sprintf("%s/v1/agent-runtime", m.workloadMgrAddr)
	} else {
		endpoint = fmt.Sprintf("%s/v1/code-interpreter", m.workloadMgrAddr)
	}

	reqBody := types.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	return m.createSandbox(ctx, endpoint, &reqBody)
}

func (m *manager) createSandbox(ctx context.Context, endpoint string, req *types.CreateSandboxRequest) (*types.SandboxInfo, error) {
	body, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, endpoint, bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}
	httpReq.Header.Set("Content-Type", "application/json")

	if m.serviceAccountToken != "" {
		httpReq.Header.Set("Authorization", "Bearer "+m.serviceAccountToken)
	}

	resp, err := m.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("failed to call workload manager: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		var errResp struct {
			Message string `json:"message"`
			Error   string `json:"error"`
		}
		if err := json.NewDecoder(resp.Body).Decode(&errResp); err != nil {
			return nil, fmt.Errorf("workload manager returned status %d", resp.StatusCode)
		}
		msg := errResp.Message
		if msg == "" {
			msg = errResp.Error
		}
		return nil, fmt.Errorf("workload manager error: %s", msg)
	}

	var createResp types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&createResp); err != nil {
		return nil, fmt.Errorf("failed to decode response: %w", err)
	}

	info := &types.SandboxInfo{
		Kind:             req.Kind,
		SandboxID:        createResp.SandboxID,
		SandboxNamespace: req.Namespace,
		Name:             createResp.SandboxName,
		SessionID:        createResp.SessionID,
		EntryPoints:      createResp.EntryPoints,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(15 * time.Minute),
		Status:           "running",
	}

	return info, nil
}

func (s *Server) Start(ctx context.Context) error {
	addr := ":" + s.config.Port
	s.httpServer = &http.Server{
		Addr:        addr,
		Handler:     s.engine,
		ReadTimeout: 30 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	klog.Infof("Starting router server on %s", addr)
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	shutdownCtx, cancel := context.WithTimeout(ctx, 10*time.Second)
	defer cancel()
	return s.httpServer.Shutdown(shutdownCtx)
}

