	return &JWTManager{
		privateKey: privateKey,
		publicKey:  &privateKey.PublicKey,
	}, nil
}

func (j *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	now := time.Now()
	jwtClaims := jwt.MapClaims{
		"exp": now.Add(jwtExpiration).Unix(),
		"iat": now.Unix(),
		"iss": "agentcube-router",
	}

	for k, v := range claims {
		jwtClaims[k] = v
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwtClaims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) LoadPublicKeyFromEnv() error {
	keyData := os.Getenv("PICOD_AUTH_PUBLIC_KEY")
	if keyData == "" {
		return errors.New("PICOD_AUTH_PUBLIC_KEY environment variable is not set")
	}

	block, _ := pem.Decode([]byte(keyData))
	if block == nil {
		return errors.New("failed to decode PEM block")
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return err
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return errors.New("not an RSA public key")
	}

	j.mu.Lock()
	j.publicKey = rsaPub
	j.mu.Unlock()

	return nil
}

func (j *JWTManager) TryStoreOrLoadJWTKeySecret() error {
	cfg, err := rest.InClusterConfig()
	if err != nil {
		if errors.Is(err, rest.ErrNotInCluster) {
			klog.Info("not running in cluster, skipping JWT identity secret creation")
			return nil
		}
		return fmt.Errorf("failed to get in-cluster config: %w", err)
	}

	clientset, err := kubernetes.NewForConfig(cfg)
	if err != nil {
		return fmt.Errorf("failed to create kubernetes client: %w", err)
	}

	j.clientset = clientset

	_, err = clientset.CoreV1().Secrets(IdentityNamespace).Get(context.Background(), IdentitySecretName, metav1.GetOptions{})
	if err == nil {
		klog.Infof("JWT identity secret %s/%s already exists", IdentityNamespace, IdentitySecretName)
		return nil
	}

	if !k8serrors.IsNotFound(err) {
		return fmt.Errorf("failed to check secret existence: %w", err)
	}

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(j.privateKey),
	})

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(j.publicKey)
	if err != nil {
		return fmt.Errorf("failed to marshal public key: %w", err)
	}
	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	})

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: IdentityNamespace,
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: privateKeyPEM,
			PublicKeyDataKey:  publicKeyPEM,
		},
	}

	_, err = clientset.CoreV1().Secrets(IdentityNamespace).Create(context.Background(), secret, metav1.CreateOptions{})
	if err != nil {
		if k8serrors.IsAlreadyExists(err) {
			klog.Infof("JWT identity secret %s/%s already exists (race condition)", IdentityNamespace, IdentitySecretName)
			return nil
		}
		return fmt.Errorf("failed to create JWT identity secret: %w", err)
	}

	klog.Infof("Created JWT identity secret %s/%s", IdentityNamespace, IdentitySecretName)
	return nil
}

func NewServer(config *Config) (*Server, error) {
	s := &Server{
		config:        config,
		storeClient:   store.Storage(),
		httpTransport: &http.Transport{IdleConnTimeout: 0, DisableCompression: false},
	}

	if config.MaxConcurrentRequests <= 0 {
		config.MaxConcurrentRequests = 1000
	}

	jwtMgr, err := NewJWTManager()
	if err != nil {
		return nil, err
	}
	s.jwtManager = jwtMgr

	sm, err := NewSessionManager(s.storeClient)
	if err != nil {
		return nil, err
	}
	s.sessionManager = sm

	if config.Debug {
		gin.SetMode(gin.DebugMode)
	} else {
		gin.SetMode(gin.ReleaseMode)
	}

	s.engine = gin.New()
	s.setupRoutes()

	return s, nil
}

func (s *Server) setupRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1 := s.engine.Group("/v1")
	v1.Use(gin.Logger(), gin.Recovery(), s.concurrencyLimitMiddleware())
	{
		v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
		v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
		v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
	}
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{"status": "not ready", "error": "session manager not available"})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) concurrencyLimitMiddleware() gin.HandlerFunc {
	sem := make(chan struct{}, s.config.MaxConcurrentRequests)
	return func(c *gin.Context) {
		select {
		case sem <- struct{}{}:
			defer func() { <-sem }()
			c.Next()
		default:
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
		}
	}
}

func (s *Server) handleAgentInvoke(c *gin.Context) {
	s.handleInvoke(c, types.AgentRuntimeKind)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	s.handleInvoke(c, types.CodeInterpreterKind)
}

func (s *Server) handleInvoke(c *gin.Context, kind string) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sessionID := c.GetHeader("x-agentcube-session-id")

	ctx := c.Request.Context()

	sandboxInfo, err := s.sessionManager.GetSandboxBySession(ctx, sessionID, namespace, name, kind)
	if err != nil {
		s.handleGetSandboxError(c, err)
		return
	}

	s.storeClient.UpdateSessionLastActivity(ctx, sandboxInfo.SessionID, time.Now())

	if err := s.forwardToSandbox(c, sandboxInfo, path); err != nil {
		s.handleProxyError(c, err)
		return
	}

	s.storeClient.UpdateSessionLastActivity(ctx, sandboxInfo.SessionID, time.Now())
}

func (s *Server) forwardToSandbox(c *gin.Context, sandboxInfo *types.SandboxInfo, path string) error {
	if len(sandboxInfo.EntryPoints) == 0 {
		c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
		return errors.New("no entry points")
	}

	var entryPoint *types.SandboxEntryPoint
	for _, ep := range sandboxInfo.EntryPoints {
		if ep.Path != "" && strings.HasPrefix(path, ep.Path) {
			entryPoint = &ep
			break
		}
	}
	if entryPoint == nil {
		entryPoint = &sandboxInfo.EntryPoints[0]
	}

	scheme := strings.ToLower(entryPoint.Protocol)
	if scheme == "" {
		scheme = "http"
	}

	targetURL := fmt.Sprintf("%s://%s", scheme, entryPoint.Endpoint)
	target, err := url.Parse(targetURL)
	if err != nil {
		return err
	}

	proxy := httputil.NewSingleHostReverseProxy(target)
	proxy.Transport = s.httpTransport

	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = target.Scheme
		req.URL.Host = target.Host
		req.URL.Path = path
		if !strings.HasPrefix(path, "/") && path != "" {
			req.URL.Path = "/" + path
		}
		req.URL.RawPath = ""
		req.Host = target.Host

		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		proto := "http"
		if c.Request.TLS != nil {
			proto = "https"
		}
		req.Header.Set("X-Forwarded-Proto", proto)

		clientIP := c.ClientIP()
		if existing := req.Header.Get("X-Forwarded-For"); existing != "" {
			req.Header.Set("X-Forwarded-For", existing+", "+clientIP)
		} else {
			req.Header.Set("X-Forwarded-For", clientIP)
		}

		if sandboxInfo.Kind == types.SandboxKind || sandboxInfo.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": sandboxInfo.SessionID,
			})
			if err != nil {
				klog.Warningf("failed to generate JWT: %v", err)
			} else {
				req.Header.Set("Authorization", "Bearer "+token)
			}
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sandboxInfo.SessionID)
		return nil
	}

	proxy.ServeHTTP(c.Writer, c.Request)
	return nil
}

func (s *Server) handleGetSandboxError(c *gin.Context, err error) {
	if apiErr, ok := err.(interface{ Status() metav1.Status }); ok {
		code := int(apiErr.Status().Code)
		if code == 0 {
			code = 500
		}
		msg := apiErr.Status().Message
		if msg == "" {
			msg = err.Error()
		}
		if code == 500 {
			msg = "internal server error"
		}
		c.JSON(code, gin.H{"error": msg})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

func (s *Server) handleProxyError(c *gin.Context, err error) {
	errMsg := err.Error()
	if strings.Contains(errMsg, "connection refused") {
		c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
		return
	}
	if strings.Contains(errMsg, "timeout") {
		c.JSON(http.StatusGatewayTimeout, gin.H{"error": "sandbox timeout"})
		return
	}
	c.JSON(http.StatusBadGateway, gin.H{"error": "sandbox unreachable"})
}

func NewSessionManager(storeClient store.Store) (SessionManager, error) {
	addr := os.Getenv("WORKLOAD_MANAGER_URL")
	if addr == "" {
		return nil, errors.New("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	serviceAccountToken := readServiceAccountToken()

	return &manager{
		storeClient:         storeClient,
		workloadMgrAddr:     addr,
		serviceAccountToken: serviceAccountToken,
		httpClient: &http.Client{
			Timeout: 2 * time.Minute,
			Transport: &http.Transport{
				MaxIdleConnsPerHost: 100,
				DisableCompression:  false,
			},
		},
	}, nil
}

func readServiceAccountToken() string {
	tokenPath := "/var/run/secrets/kubernetes.io/serviceaccount/token"
	data, err := os.ReadFile(tokenPath)
	if err != nil {
		klog.V(4).Infof("could not read service account token: %v", err)
		return ""
	}
	return string(data)
}

