func (s *Server) handleInvoke(c *gin.Context, kind string) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")

	sessionID := c.GetHeader("x-agentcube-session-id")

	ctx := c.Request.Context()

	sandboxInfo, err := s.sessionManager.GetSandboxBySession(ctx, sessionID, namespace, name, kind)
	if err != nil {
		s.handleGetSandboxError(c, err)
		return
	}

	s.storeClient.UpdateSessionLastActivity(ctx, sandboxInfo.SessionID, time.Now())

	if err := s.forwardToSandbox(c, sandboxInfo, path); err != nil {
		s.handleProxyError(c, err)
		return
	}

	s.storeClient.UpdateSessionLastActivity(ctx, sandboxInfo.SessionID, time.Now())
