		case ch <- struct{}{}:
		default:
		}
	}
}

func (r *SandboxReconciler) Reconcile(ctx context.Context, req types.NamespacedName) error {
	sandbox, err := r.k8sClient.dynamicClient.Resource(SandboxGVR).Namespace(req.Namespace).Get(ctx, req.Name, metav1.GetOptions{})
	if err != nil {
		if errors.IsNotFound(err) {
			return nil
		}
		return err
	}

	status := sandbox.Object["status"]
	if status == nil {
		return nil
	}

	statusMap, ok := status.(map[string]interface{})
	if !ok {
		return nil
	}

	conditions, ok := statusMap["conditions"].([]interface{})
	if !ok {
		return nil
	}

	for _, c := range conditions {
		cond, ok := c.(map[string]interface{})
		if !ok {
			continue
		}
		if cond["type"] == "Ready" && cond["status"] == "True" {
			r.NotifySandboxRunning(req.Namespace, req.Name)
			break
		}
	}

	return nil
}

