func loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		c.Next()
		klog.Infof("%s %s %d %v", c.Request.Method, c.Request.URL.Path, c.Writer.Status(), time.Since(start))
	}
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, ErrorResponse{Message: "Missing authorization header"})
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, ErrorResponse{Message: "Invalid authorization header format"})
			return
		}

		token := parts[1]
		username, err := s.validateServiceAccountToken(c.Request.Context(), token)
		if err != nil {
			c.AbortWithStatusJSON(http.StatusUnauthorized, ErrorResponse{Message: "Invalid token"})
			return
		}

		c.Set("userToken", token)
		c.Set("username", username)
		c.Next()
	}
}

func (s *Server) validateServiceAccountToken(ctx context.Context, token string) (string, error) {
	if username, ok := s.tokenCache.Get(token); ok {
		return username, nil
	}

	review := &corev1.TokenReview{
		Spec: corev1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := s.k8sClient.clientset.AuthenticationV1().TokenReviews().Create(ctx, review, metav1.CreateOptions{})
	if err != nil {
		return "", err
	}

	if !result.Status.Authenticated {
		return "", errors.New("token not authenticated")
	}

	username := result.Status.User.Username
	s.tokenCache.Set(token, username)

	return username, nil
}

func (s *Server) initK8sClient() error {
	config, err := rest.InClusterConfig()
	if err != nil {
		config, err = rest.DefaultClientConfig(&rest.Config{}).ClientConfig()
		if err != nil {
			return err
		}
	}

	config.QPS = 50
	config.Burst = 100

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return err
	}

	dynamicClient, err := dynamic.NewForConfig(config)
	if err != nil {
		return err
	}

	s.k8sClient = &K8sClient{
		clientset:     clientset,
		dynamicClient: dynamicClient,
		baseConfig:    config,
		clientCache:   NewClientCache(100),
	}

	return nil
}

func (s *Server) Start(ctx context.Context) error {
	addr := ":" + s.config.Port
	s.httpServer = &http.Server{
		Addr:        addr,
		Handler:     s.router,
		ReadTimeout: 15 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	if err := s.storeClient.Ping(ctx); err != nil {
		return fmt.Errorf("store ping failed: %w", err)
	}

	go s.runGarbageCollector(ctx)

	klog.Infof("Starting workload manager server on %s", addr)
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	shutdownCtx, cancel := context.WithTimeout(ctx, 15*time.Second)
	defer cancel()
	return s.httpServer.Shutdown(shutdownCtx)
}

func (s *Server) runGarbageCollector(ctx context.Context) {
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			s.garbageCollect(ctx)
		}
	}
}

func (s *Server) garbageCollect(ctx context.Context) {
	gcCtx, cancel := context.WithTimeout(ctx, 2*time.Minute)
	defer cancel()

	inactiveCutoff := time.Now().Add(-DefaultSandboxIdleTimeout)
	inactive, err := s.storeClient.ListInactiveSandboxes(gcCtx, inactiveCutoff, 16)
	if err != nil {
		klog.Warningf("failed to list inactive sandboxes: %v", err)
	}

	expired, err := s.storeClient.ListExpiredSandboxes(gcCtx, time.Now(), 16)
	if err != nil {
		klog.Warningf("failed to list expired sandboxes: %v", err)
	}

	seen := make(map[string]bool)
	for _, sandbox := range append(inactive, expired...) {
		if seen[sandbox.SessionID] {
			continue
		}
		seen[sandbox.SessionID] = true

		var gvr schema.GroupVersionResource
		if sandbox.Kind == types.SandboxClaimsKind {
			gvr = SandboxClaimGVR
		} else {
			gvr = SandboxGVR
		}

		err := s.k8sClient.dynamicClient.Resource(gvr).Namespace(sandbox.SandboxNamespace).Delete(gcCtx, sandbox.Name, metav1.DeleteOptions{})
		if err != nil && !errors.Is(err, metav1.ErrNotFound) {
			klog.Warningf("failed to delete sandbox %s: %v", sandbox.Name, err)
			continue
		}

		s.storeClient.DeleteSandboxBySessionID(gcCtx, sandbox.SessionID)
	}
}

