func (s *Server) createSandbox(ctx context.Context, req *types.CreateSandboxRequest, kind string) (*types.CreateSandboxResponse, error) {
	sessionID := uuid.New().String()
	sandboxID := uuid.New().String()
	sandboxName := fmt.Sprintf("%s-%s", req.Name, sandboxID[:8])

	sandboxInfo := &types.SandboxInfo{
		Kind:             kind,
		SandboxID:        sandboxID,
		SandboxNamespace: req.Namespace,
		Name:             sandboxName,
		SessionID:        sessionID,
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
		Status:           "pending",
	}

	if err := s.storeClient.StoreSandbox(ctx, sandboxInfo); err != nil {
		return nil, err
	}

	sandboxObj := s.buildSandboxObject(sandboxInfo, req, kind)

	watchCh := s.sandboxController.WatchSandboxOnce(sandboxInfo.SandboxNamespace, sandboxInfo.Name)

	dynamicClient := s.k8sClient.dynamicClient
	gvr := SandboxGVR
	unstructuredObj := &unstructured.Unstructured{Object: sandboxObj}
	_, err := dynamicClient.Resource(gvr).Namespace(sandboxInfo.SandboxNamespace).Create(ctx, unstructuredObj, metav1.CreateOptions{})
	if err != nil {
		s.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
		return nil, err
	}

	select {
	case <-watchCh:
		podIP, err := s.resolvePodIP(ctx, sandboxInfo)
		if err != nil {
			s.rollbackSandbox(ctx, sandboxInfo, kind)
			return nil, fmt.Errorf("failed to resolve pod IP: %w", err)
		}

		entryPoints := s.buildEntryPoints(sandboxInfo, podIP)
		sandboxInfo.EntryPoints = entryPoints
		sandboxInfo.Status = "running"

		if err := s.storeClient.UpdateSandbox(ctx, sandboxInfo); err != nil {
			klog.Warningf("failed to update sandbox: %v", err)
		}

		return &types.CreateSandboxResponse{
			SessionID:   sessionID,
			SandboxID:   sandboxID,
			SandboxName: sandboxName,
			EntryPoints: entryPoints,
		}, nil
	case <-time.After(2 * time.Minute):
		s.rollbackSandbox(ctx, sandboxInfo, kind)
		return nil, errors.New("sandbox creation timed out")
	case <-ctx.Done():
		s.rollbackSandbox(ctx, sandboxInfo, kind)
		return nil, ctx.Err()
	}
}

func (s *Server) rollbackSandbox(ctx context.Context, sandboxInfo *types.SandboxInfo, kind string) {
	deleteCtx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	gvr := SandboxGVR
	s.k8sClient.dynamicClient.Resource(gvr).Namespace(sandboxInfo.SandboxNamespace).Delete(deleteCtx, sandboxInfo.Name, metav1.DeleteOptions{})
	s.storeClient.DeleteSandboxBySessionID(ctx, sandboxInfo.SessionID)
}

func (s *Server) resolvePodIP(ctx context.Context, sandboxInfo *types.SandboxInfo) (string, error) {
	podName := sandboxInfo.Name

	pod, err := s.k8sClient.podLister.Pods(sandboxInfo.SandboxNamespace).Get(podName)
	if err != nil {
		return "", err
	}

	if pod.Status.Phase != corev1.PodRunning {
		return "", fmt.Errorf("pod is not running: %s", pod.Status.Phase)
	}

	if pod.Status.PodIP == "" {
		return "", errors.New("pod has no IP")
	}

	return pod.Status.PodIP, nil
}

func (s *Server) buildEntryPoints(sandboxInfo *types.SandboxInfo, podIP string) []types.SandboxEntryPoint {
	return []types.SandboxEntryPoint{
		{
			Path:     "/",
			Protocol: "HTTP",
			Endpoint: fmt.Sprintf("%s:8080", podIP),
		},
	}
}

func (s *Server) buildSandboxObject(sandboxInfo *types.SandboxInfo, req *types.CreateSandboxRequest, kind string) map[string]interface{} {
	return map[string]interface{}{
		"apiVersion": "agents.x-k8s.io/v1alpha1",
		"kind":       "Sandbox",
		"metadata": map[string]interface{}{
			"name":      sandboxInfo.Name,
			"namespace": sandboxInfo.SandboxNamespace,
			"labels": map[string]string{
				"managed-by":         "agentcube-workload-manager",
				SessionIdLabelKey:    sandboxInfo.SessionID,
				WorkloadNameLabelKey: req.Name,
				SandboxNameLabelKey:  sandboxInfo.Name,
			},
			"annotations": map[string]string{
				LastActivityAnnotationKey: time.Now().Format(time.RFC3339),
				IdleTimeoutAnnotationKey:  DefaultSandboxIdleTimeout.String(),
			},
		},
		"spec": map[string]interface{}{
			"lifecycle": map[string]interface{}{
				"shutdownTime": time.Now().Add(DefaultSandboxTTL).Format(time.RFC3339),
			},
			"replicas": 1,
		},
	}
}

func (s *Server) handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("sessionId")

	sandboxInfo, err := s.storeClient.GetSandboxBySessionID(c.Request.Context(), sessionID)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			c.JSON(http.StatusNotFound, ErrorResponse{Message: fmt.Sprintf("Session ID %s not found, maybe already deleted", sessionID)})
			return
		}
		s.handleError(c, err)
		return
	}

	var gvr schema.GroupVersionResource
	if sandboxInfo.Kind == types.SandboxClaimsKind {
		gvr = SandboxClaimGVR
	} else {
		gvr = SandboxGVR
	}

	err = s.k8sClient.dynamicClient.Resource(gvr).Namespace(sandboxInfo.SandboxNamespace).Delete(c.Request.Context(), sandboxInfo.Name, metav1.DeleteOptions{})
	if err != nil && !apierrors.IsNotFound(err) {
		s.handleError(c, err)
		return
	}

	s.storeClient.DeleteSandboxBySessionID(c.Request.Context(), sessionID)

	c.JSON(http.StatusOK, gin.H{"message": "Sandbox deleted successfully"})
}

func (s *Server) handleError(c *gin.Context, err error) {
	klog.Errorf("error handling request: %v", err)
	c.JSON(http.StatusInternalServerError, ErrorResponse{Message: "internal server error"})
}

func loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		c.Next()
		klog.Infof("%s %s %d %v", c.Request.Method, c.Request.URL.Path, c.Writer.Status(), time.Since(start))
	}
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, ErrorResponse{Message: "Missing authorization header"})
			return
		}

		parts := strings.Split(authHeader, " ")
		if len(parts) != 2 || parts[0] != "Bearer" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, ErrorResponse{Message: "Invalid authorization header format"})
			return
		}

		token := parts[1]
		username, err := s.validateServiceAccountToken(c.Request.Context(), token)
		if err != nil {
			c.AbortWithStatusJSON(http.StatusUnauthorized, ErrorResponse{Message: "Invalid token"})
			return
		}

		c.Set("userToken", token)
		c.Set("username", username)
		c.Next()
	}
}

func (s *Server) validateServiceAccountToken(ctx context.Context, token string) (string, error) {
	if username, ok := s.tokenCache.Get(token); ok {
		return username, nil
	}

	review := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := s.k8sClient.clientset.AuthenticationV1().TokenReviews().Create(ctx, review, metav1.CreateOptions{})
	if err != nil {
		return "", err
	}

	if !result.Status.Authenticated {
		return "", errors.New("token not authenticated")
	}

	username := result.Status.User.Username
	s.tokenCache.Set(token, username)

	return username, nil
}

func (s *Server) initK8sClient() error {
	config, err := rest.InClusterConfig()
	if err != nil {
		kubeconfig := clientcmd.NewDefaultClientConfigLoadingRules().GetDefaultFilename()
		config, err = clientcmd.BuildConfigFromFlags("", kubeconfig)
		if err != nil {
			return err
		}
	}

	config.QPS = 50
	config.Burst = 100

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return err
	}

	dynamicClient, err := dynamic.NewForConfig(config)
	if err != nil {
		return err
	}

	s.k8sClient = &K8sClient{
		clientset:     clientset,
		dynamicClient: dynamicClient,
		baseConfig:    config,
		clientCache:   NewClientCache(100),
	}

	return nil
}

func (s *Server) Start(ctx context.Context) error {
	addr := ":" + s.config.Port

	h2s := &http2.Server{}
	handler := h2c.NewHandler(s.router, h2s)

	s.httpServer = &http.Server{
		Addr:        addr,
		Handler:     handler,
		ReadTimeout: 15 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	if err := s.storeClient.Ping(ctx); err != nil {
		return fmt.Errorf("store ping failed: %w", err)
	}

	if s.informers != nil {
		syncCtx, cancel := context.WithTimeout(ctx, time.Minute)
		defer cancel()
		if err := s.informers.WaitForSync(syncCtx); err != nil {
			return fmt.Errorf("failed to sync informers: %w", err)
		}
	}

	go s.runGarbageCollector(ctx)

	klog.Infof("Starting workload manager server on %s", addr)
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	shutdownCtx, cancel := context.WithTimeout(ctx, 15*time.Second)
	defer cancel()
	return s.httpServer.Shutdown(shutdownCtx)
}

func (s *Server) runGarbageCollector(ctx context.Context) {
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			s.garbageCollect(ctx)
		}
	}
}

func (s *Server) garbageCollect(ctx context.Context) {
	gcCtx, cancel := context.WithTimeout(ctx, 2*time.Minute)
	defer cancel()

	inactiveCutoff := time.Now().Add(-DefaultSandboxIdleTimeout)
	inactive, err := s.storeClient.ListInactiveSandboxes(gcCtx, inactiveCutoff, 16)
	if err != nil {
		klog.Warningf("failed to list inactive sandboxes: %v", err)
	}

	expired, err := s.storeClient.ListExpiredSandboxes(gcCtx, time.Now(), 16)
	if err != nil {
		klog.Warningf("failed to list expired sandboxes: %v", err)
	}

	seen := make(map[string]bool)
	for _, sandbox := range append(inactive, expired...) {
		if seen[sandbox.SessionID] {
			continue
		}
		seen[sandbox.SessionID] = true

		var gvr schema.GroupVersionResource
		if sandbox.Kind == types.SandboxClaimsKind {
			gvr = SandboxClaimGVR
		} else {
			gvr = SandboxGVR
		}

		err := s.k8sClient.dynamicClient.Resource(gvr).Namespace(sandbox.SandboxNamespace).Delete(gcCtx, sandbox.Name, metav1.DeleteOptions{})
		if err != nil && !apierrors.IsNotFound(err) {
			klog.Warningf("failed to delete sandbox %s: %v", sandbox.Name, err)
			continue
		}

		s.storeClient.DeleteSandboxBySessionID(gcCtx, sandbox.SessionID)
	}
}

